K is achievable iff K >= min_insertions and (K - min_insertions) is even.

```python
import sys
input = sys.stdin.readline

def lps(s):
    n = len(s)
    dp = [[0]*n for _ in range(n)]
    for i in range(n-1, -1, -1):
        dp[i][i] = 1
        for j in range(i+1, n):
            if s[i] == s[j]:
                dp[i][j] = dp[i+1][j-1] + 2
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j-1])
    return dp[0][n-1]

def solve():
    s = input().strip()
    k = int(input())
    min_ins = len(s) - lps(s)
    if k >= min_ins and (k - min_ins) % 2 == 0:
        print("Yes")
    else:
        print("No")

T = int(input())
for _ in range(T):
    solve()
```

