Precompute L, R, T, B for each cell via directional sweeps. Count non-wall cells where min(L,R,T,B) >= 2.

```python
import sys
input = sys.stdin.readline

def solve():
    r, c = map(int, input().split())
    grid = [input().strip() for _ in range(r)]

    L = [[0]*c for _ in range(r)]
    R = [[0]*c for _ in range(r)]
    T = [[0]*c for _ in range(r)]
    B = [[0]*c for _ in range(r)]

    for i in range(r):
        for j in range(1, c):
            if grid[i][j-1] == '^':
                L[i][j] = L[i][j-1] + 1
        for j in range(c-2, -1, -1):
            if grid[i][j+1] == '^':
                R[i][j] = R[i][j+1] + 1
    for j in range(c):
        for i in range(1, r):
            if grid[i-1][j] == '^':
                T[i][j] = T[i-1][j] + 1
        for i in range(r-2, -1, -1):
            if grid[i+1][j] == '^':
                B[i][j] = B[i+1][j] + 1

    count = 0
    for i in range(r):
        for j in range(c):
            if grid[i][j] != '#' and min(L[i][j], R[i][j], T[i][j], B[i][j]) >= 2:
                count += 1
    print(count)

T_cases = int(input())
for _ in range(T_cases):
    solve()
```

