Simulate: 'L'->leftmost free, 'R'->rightmost free, digit d->vacate room d.

```python
import sys
input = sys.stdin.readline

def solve():
    s = input().strip()
    rooms = [0] * 10
    for event in s:
        if event == 'L':
            for i in range(10):
                if rooms[i] == 0:
                    rooms[i] = 1
                    break
        elif event == 'R':
            for i in range(9, -1, -1):
                if rooms[i] == 0:
                    rooms[i] = 1
                    break
        else:
            rooms[int(event)] = 0
    print(''.join(map(str, rooms)))

T = int(input())
for _ in range(T):
    solve()
```
